    "additionalProperties": false,
    "properties": {
      "data-set-name": {
        "description": "Optional — narrow the result to a single dataset name (e.g. 'apm.metric.apm.service'). Omit to return every dataset of the given type.",
        "type": "string"
      },
      "data-set-type": {
        "description": "Type of data set to discover. Omit to discover all types (metric_set, log_set, trace_set, event_set, profile_set).",
        "enum": [
          "metric_set",
          "log_set",
          "trace_set",
          "event_set",
          "profile_set"
        ],
        "type": "string"
      },
      "entity-domain": {
        "description": "Entity domain (e.g. apm, k8s, acs). CLI flag: --entity-domain.",
        "type": "string"
      },
      "entity-ids": {
        "description": "One or more entity IDs whose datasets and storage should be grouped together. Get from entity search.",
        "items": {
          "type": "string"
        },
        "type": "array"
      },
      "entity-type": {
        "description": "Entity type (e.g. apm.service, k8s.pod, k8s.node). CLI flag: --entity-type.",
        "type": "string"
      },
      "from": {
        "description": "Range start; must be paired with --to. Ignored when --time-range is set (e.g. now-1h, 2024-01-01 10:00:00).",
        "type": "string"
      },
      "time-range": {
        "description": "Time range for the query. Either pass this (e.g. last_1h, now-15m~now, today, 2024-01-01~now) or pass both --from and --to; one of the two forms is required — there is no implicit default.",
